create table public.users (id uuid primary key references auth.users on delete cascade, email text not null, display_name text, is_demo boolean not null default false, created_at timestamptz not null default now());
create table public.pantry_items (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.users on delete cascade, name text not null, category text not null, quantity numeric not null check (quantity > 0), unit text not null, estimated_price numeric check (estimated_price >= 0), purchased_at date, expires_at date, source text not null check (source in ('receipt','manual')), created_at timestamptz not null default now());
create table public.receipts (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.users on delete cascade, image_url text, raw_ocr_json jsonb, parsed_at timestamptz, total_amount numeric, store_name text);
create table public.recipes (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.users on delete cascade, title text not null, ingredients_json jsonb not null, steps_json jsonb not null, time_minutes integer, missing_ingredients_json jsonb, estimated_cost numeric, created_at timestamptz not null default now(), source text not null check (source in ('ai_generated','saved')));
create table public.chat_sessions (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.users on delete cascade, recipe_id uuid references public.recipes on delete set null, created_at timestamptz not null default now());
create table public.chat_messages (id uuid primary key default gen_random_uuid(), session_id uuid not null references public.chat_sessions on delete cascade, role text not null check (role in ('user','assistant')), content text not null, youtube_links_json jsonb, created_at timestamptz not null default now());
create table public.spend_log (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.users on delete cascade, week_start date not null, total_spent numeric not null default 0, total_meals_cooked integer not null default 0, est_savings numeric not null default 0, unique(user_id, week_start));
create table public.ai_jobs (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.users on delete cascade, kind text not null, status text not null default 'queued' check (status in ('queued','processing','completed','failed')), payload jsonb not null, result jsonb, created_at timestamptz not null default now(), completed_at timestamptz);
create index pantry_items_user_id_idx on public.pantry_items(user_id); create index receipts_user_id_idx on public.receipts(user_id); create index recipes_user_id_idx on public.recipes(user_id); create index chat_sessions_user_id_idx on public.chat_sessions(user_id); create index ai_jobs_user_status_idx on public.ai_jobs(user_id,status);
alter table public.users enable row level security; alter table public.pantry_items enable row level security; alter table public.receipts enable row level security; alter table public.recipes enable row level security; alter table public.chat_sessions enable row level security; alter table public.chat_messages enable row level security; alter table public.spend_log enable row level security; alter table public.ai_jobs enable row level security;
create policy "users own profile" on public.users for all using (id = auth.uid()) with check (id = auth.uid());
create policy "users own pantry" on public.pantry_items for all using (user_id = auth.uid()) with check (user_id = auth.uid());
create policy "users own receipts" on public.receipts for all using (user_id = auth.uid()) with check (user_id = auth.uid());
create policy "users own recipes" on public.recipes for all using (user_id = auth.uid()) with check (user_id = auth.uid());
create policy "users own sessions" on public.chat_sessions for all using (user_id = auth.uid()) with check (user_id = auth.uid());
create policy "users own messages" on public.chat_messages for all using (exists (select 1 from public.chat_sessions s where s.id = session_id and s.user_id = auth.uid())) with check (exists (select 1 from public.chat_sessions s where s.id = session_id and s.user_id = auth.uid()));
create policy "users own spend log" on public.spend_log for all using (user_id = auth.uid()) with check (user_id = auth.uid());
create policy "users own jobs" on public.ai_jobs for all using (user_id = auth.uid()) with check (user_id = auth.uid());
insert into storage.buckets (id, name, public) values ('receipts','receipts',false) on conflict do nothing;
create policy "private receipt upload" on storage.objects for insert to authenticated with check (bucket_id = 'receipts' and (storage.foldername(name))[1] = auth.uid()::text);
create policy "private receipt read" on storage.objects for select to authenticated using (bucket_id = 'receipts' and (storage.foldername(name))[1] = auth.uid()::text);
